#include<bits/stdc++.h>
using namespace std;
int fa[200010],u[200010],v[200010],w[200010];
int n,m,cnt;
bool vis[200010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    int a=find(x),b=find(y);
    if(a!=b)
    {
        fa[a]=b;
        cnt--;
    }
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
    int n,m;
    scanf("%d%d",&n,&m);
    memset(vis,0,sizeof(vis));
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&u[i],&v[i],&w[i]);
    }
    int ans=0;
    for(int x=30;x>=0;x--)
    {
        cnt=n;
        for(int i=1;i<=n;i++)
        {
            fa[i]=i;
        }
        for(int i=1;i<=m;i++)
        {
            if((!vis[i])&&(!(w[i]&(1<<x))))
            {
                merge(u[i],v[i]);
            }
        }
        if(cnt==1)
        {
            for(int i=1;i<=m;i++)
            {
                if(w[i]&(1<<x))
                {
                    vis[i]=1;
                }
            }
        }
        else
        {
            ans+=(1<<x);
        }
    }
    printf("%d\n",ans);
    }
    return 0;
}
